class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int ones = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] == 1) ones++;
        }

        if (ones == 0) return 0;

        int minSwaps = INT_MAX;
        for (int i = 0; i < n; i++) {
            int swaps = 0;
            int j = i;
            while (nums[j] != 1) {
                j = (j + 1) % n;
                swaps++;
            }
            int k = j;
            while (k != i) {
                swaps++;
                k = (k + 1) % n;
            }
            minSwaps = min(minSwaps, swaps);
        }

        return minSwaps;
    }
};
```

